#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<ll, ll>PII
using namespace std;
CI MAXN=1e3+5;
char maps[MAXN][MAXN];
int fjx,fjy,fjd=1,cox,coy,cod=1,times=0;
void fj()//FJ的移动 
{
	if(fjd==1&&maps[fjx-1][fjy]!='*') fjx=fjx-1;
	else if(fjd==2&&maps[fjx][fjy+1]!='*') fjy=fjy+1;
	else if(fjd==3&&maps[fjx+1][fjy]!='*') fjx=fjx+1;
	else if(fjd==4&&maps[fjx][fjy-1]!='*') fjy=fjy-1;   
	else if(fjd!=4) fjd=fjd+1;
	else fjd=1;
}
void co()//塔姆沃斯牛的移动 
{
	if(cod==1&&maps[cox-1][coy]!='*') cox=cox-1;
	else if(cod==2&&maps[cox][coy+1]!='*') coy=coy+1;
	else if(cod==3&&maps[cox+1][coy]!='*') cox=cox+1;
	else if(cod==4&&maps[cox][coy-1]!='*') coy=coy-1;   
	else if(cod!=4) cod=cod+1;
	else cod=1;
}
int main(void){
	//输入 
	memset(maps,'*',sizeof maps);
	for(int i=1;i<=10;++i)
		for(int j=1;j<=10;++j)
			cin>>maps[i][j];
	//寻找位置 
	for(int i=1;i<=10;++i)
	{
		for(int j=1;j<=10;++j)
		{
			if(maps[i][j]=='F')
				fjx=i,fjy=j;//FJ的位置 
			if(maps[i][j]=='C')
				cox=i,coy=j;//塔姆沃斯牛的位置 
		}
	}
	//模拟过程 
	while(((fjx!=cox)||(fjy!=coy))&&times<10000)
	{
		fj();//FJ移动
		co();//塔姆沃斯牛移动
		times+=1;//过一分钟 
	}	
	//输出 
	if(times==10000) printf("0");
	else printf("%d",times);
	return false;
}
